// Build Medika SaveTransferOrder request payload
const input = $('Sub-Workflow Input').first().json;
const config = input.config || {};
const lines = input.validatedLines || [];

const submittableLines = lines.filter(l => l.articleId && l.valid !== false);
const skippedLines = lines.filter(l => !l.articleId || l.valid === false);

const orderPayload = {
  BusinessCenter: input.businessCenter || config.businessCenterDefault || '10',
  Customer: input.customer || '',
  DeliveryPlace: input.deliveryPlace || '',
  CustomerOrderNumber: 'MP-' + (input.emailId || '').substring(0, 8) + '-' + Date.now(),
  CustomerOrderDate: (input.receivedAt || new Date().toISOString()).split('T')[0],
  Text: input.emailSubject || 'Prednarudžba',
  Items: submittableLines.map(line => ({
    ArticleID: String(line.articleId),
    ArticleDescCustomer: line.articleName || '',
    Quantity: parseFloat(line.quantity) || 0,
    DiscountPerc: parseFloat(line.discountPerc) || 0.0,
    Message: line.notes || ''
  }))
};

return [{
  json: {
    config: config,
    accessToken: $('WF-00b: Get Token').first().json.accessToken,
    orderPayload: orderPayload,
    submittedLineCount: submittableLines.length,
    skippedLineCount: skippedLines.length,
    skippedLines: skippedLines
  }
}];

// Process Medika SaveTransferOrder response
const apiResponse = $input.first().json;
const buildResult = $('Build API Payload').first().json;

return [{
  json: {
    submitted: true,
    orderId: apiResponse.OrderID || null,
    status: apiResponse.Status || null,
    statusText: apiResponse.Status === 1 ? 'Received' : apiResponse.Status === 2 ? 'In process' : apiResponse.Status === 3 ? 'Processed' : 'Unknown',
    customerOrderNumber: apiResponse.CustomerOrderNumber || buildResult.orderPayload.CustomerOrderNumber,
    submittedLineCount: buildResult.submittedLineCount,
    skippedLineCount: buildResult.skippedLineCount,
    apiResponse: apiResponse,
    submittedAt: new Date().toISOString()
  }
}];

// DRY RUN: Preview the exact HTTP request that would be sent to the API
const input = $input.first().json;
const config = input.config || {};
const apiUrl = ($('Config').first().json.erpApiUrl || '') + '/api/SaveTransferOrder';

return [{
  json: {
    _mode: 'DRY_RUN',
    _note: 'This is a preview of the API request. No actual call was made.',
    request: {
      method: 'POST',
      url: apiUrl,
      headers: {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer ' + (input.accessToken ? input.accessToken.substring(0, 20) + '...' : '(no token)')
      },
      body: input.orderPayload
    },
    summary: {
      submittedLineCount: input.submittedLineCount,
      skippedLineCount: input.skippedLineCount,
      skippedLines: input.skippedLines,
      customerOrderNumber: input.orderPayload.CustomerOrderNumber,
      customer: input.orderPayload.Customer,
      deliveryPlace: input.orderPayload.DeliveryPlace,
      itemCount: (input.orderPayload.Items || []).length
    },
    submitted: true,
    orderId: 'DRY-RUN-' + Date.now(),
    submittedAt: new Date().toISOString()
  }
}];
